    "import numpy as np\n",
    "import os\n",
    "\n",
    "output_dir = os.path.expanduser('~/Desktop/accidents_clean')\n",
    "os.makedirs(output_dir, exist_ok=True)\n",
    "\n",
    "caract_clean    = caract.copy()\n",
    "lieux_clean     = lieux.copy()\n",
    "vehicules_clean = vehicules.copy()\n",
    "general_clean   = general.copy()\n",
    "\n",
    "caract_clean.to_csv(f'{output_dir}/caract_clean.csv', index=False)\n",
    "lieux_clean.to_csv(f'{output_dir}/lieux_clean.csv', index=False)\n",
    "vehicules_clean.to_csv(f'{output_dir}/vehicules_clean.csv', index=False)\n",
    "general_clean.to_csv(f'{output_dir}/general_clean.csv', index=False)\n",
    "\n",
    "lieux_clean.drop(columns = ['v2', 'lartpc'], inplace = True) #v2 %91.6 missing, Lartpc %99.9 missing\n",
    "vehicules_clean.drop(columns = ['occutc'], inplace = True) #occutc %99 missing\n",
    "before = len(lieux_clean)\n",
    "lieux.drop_duplicates(inplace = True)\n",
    "after = len(lieux_clean)\n",
    "print(f\"Lieux : {before - after} delete all duplicate values\")\n",
    "\n",
    "#lat and long string to float\n",
    "caract_clean['lat'] = caract_clean['lat'].astype(str).str.replace(',', '.').str.strip()\n",
    "caract_clean['long'] = caract_clean['long'].astype(str).str.replace(',', '.').str.strip()\n",
    "caract_clean['lat'] = pd.to_numeric(caract_clean['lat'], errors = 'coerce')\n",
    "caract_clean['long'] = pd.to_numeric(caract_clean['long'], errors = 'coerce')\n",
    "\n",
    "#hours string to integer\n",
    "caract_clean['heure'] = caract_clean['hrmn'].astype(str).str.split(':').str[0]\n",
    "caract_clean['heure'] = pd.to_numeric(caract_clean['heure'], errors = 'coerce')\n",
    "\n",
    "#dep string\n",
    "caract_clean['dep'] = caract_clean['dep'].astype(str).str.strip()\n",
    "\n",
    "print(\"variables changed\")\n",
    "print(caract_clean[['lat', 'long', 'heure', 'dep']].dtypes)\n",
    "\n",
    "#replace -1 to NaN for caract table\n",
    "cols_with_minus1 = ['col', 'atm', 'lum', 'int']\n",
    "for col in cols_with_minus1:\n",
    "    if col in caract_clean.columns:\n",
    "        caract_clean[col] = caract_clean[col].replace(-1, np.nan)\n",
    "\n",
    "#replace -1 to NaN for vehicules table\n",
    "cols_veh = ['obs', 'obsm', 'choc', 'manv', 'motor', 'senc']\n",
    "for col in cols_veh:\n",
    "    if col in vehicules_clean.columns:\n",
    "        vehicules_clean[col] = vehicules_clean[col].replace(-1, np.nan)\n",
    "        \n",
    "print(\"replaced -1 values to NaN\")\n",
    "\n",
    "print(f\"caract    : {caract_clean.shape}\")\n",
    "print(f\"lieux     : {lieux_clean.shape}\")\n",
    "print(f\"vehicules : {vehicules_clean.shape}\")\n",
    "print(f\"general   : {general_clean.shape}\")\n",
